def _resolve_dynamic_defaults(self, ctx: Context) -> None:
    """Resolve options whose ``default`` is a dynamic-default mapping
    (``{"--source-option": {value: default, ...}}``) now that every
    option has been parsed. Only applies to options whose value still
    comes from :attr:`ParameterSource.DEFAULT`.
    """
    params = self.get_params(ctx)

    for param in params:
        if not isinstance(param, Option) or not isinstance(param.default, dict):
            continue

        if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:  # type: ignore[arg-type]
            continue

        resolved = None

        for source_opt, mapping in param.default.items():
            source_param = next(
                (
                    p
                    for p in params
                    if isinstance(p, Option) and source_opt in p.opts
                ),
                None,
            )

            if source_param is None:
